        setIsEditing(true);
        setUserForm({
            id: user.id || '',
            firstName: user.firstName,
            lastName: user.lastName,
            email: user.email || '',
            phone: user.phone,
            role: user.type,
            location: user.address,
            vehicleType: user.vehicleType || '',
            permissions: user.permissions || []
        });
        setShowUserModal(true);
